#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=1e5+10,M=3e5+10;

struct Edge{
    int u,v,w;
}edge[M];

inline bool cmp(Edge x,Edge y){
    return x.w<y.w;
}

int n,m,f[N],p[N][17],dep[N],h[N][17][2];
long long sum,ans=1e18;
vector<pii> g[N];

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    for(pii y:g[x])
        if(y.x!=fa){
            int v=y.x;
            p[v][0]=x;
            h[v][0][0]=y.y;
            for(int i=1;(1<<i)<=dep[x];i++){
                p[v][i]=p[p[v][i-1]][i-1];
                h[v][i][0]=h[v][i-1][0];
                h[v][i][1]=h[v][i-1][1];
                if(h[v][i][0]<h[p[v][i-1]][i-1][0]){
                    h[v][i][1]=max(h[v][i][0],h[p[v][i-1]][i-1][1]);
                    h[v][i][0]=h[p[v][i-1]][i-1][0];
                }
                if(h[v][i][0]==h[p[v][i-1]][i-1][0])
                    h[v][i][1]=max(h[v][i][1],h[p[v][i-1]][i-1][1]);
                if(h[v][i][0]>h[p[v][i-1]][i-1][0])
                    h[v][i][1]=max(h[v][i][1],h[p[v][i-1]][i-1][0]);
            }
            /*
            printf("to: %d\n",v);
            for(int i=0;(1<<i)<=dep[x];i++)
                printf("%d ",p[v][i]);
            puts("");
            for(int i=0;(1<<i)<=dep[x];i++)
                printf("(%d, %d) ",h[v][i][0],h[v][i][1]);
            puts("");
            */
            dfs(v,x);
        }
}

pii LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    pair<int,int> res=make_pair(-1e9,-1e9);
    for(int i=16;i>=0;i--)
        if(dep[p[x][i]]>=dep[y]){
            if(res.x<h[x][i][0]){
                res.y=max(res.x,h[x][i][1]);
                res.x=h[x][i][0];
            }
            if(res.x==h[x][i][0])
                res.y=max(res.y,h[x][i][1]);
            if(res.x>h[x][i][0])
                res.y=max(res.y,h[x][i][0]);
            x=p[x][i];
        }
    if(x==y)
        return res;
    for(int i=16;i>=0;i--)
        if(p[x][i]!=p[y][i]){
            if(res.x<h[x][i][0]){
                res.y=max(res.x,h[x][i][1]);
                res.x=h[x][i][0];
            }
            if(res.x==h[x][i][0])
                res.y=max(res.y,h[x][i][1]);
            if(res.x>h[x][i][0])
                res.y=max(res.y,h[x][i][0]);
            x=p[x][i];
            if(res.x<h[y][i][0]){
                res.y=max(res.x,h[y][i][1]);
                res.x=h[y][i][0];
            }
            if(res.x==h[y][i][0])
                res.y=max(res.y,h[y][i][1]);
            if(res.x>h[y][i][0])
                res.y=max(res.y,h[y][i][0]);
            y=p[y][i];
        }
    if(res.x<h[x][0][0]){
        res.y=max(res.x,h[x][0][1]);
        res.x=h[x][0][0];
    }
    if(res.x==h[x][0][0])
        res.y=max(res.y,h[x][0][1]);
    if(res.x>h[x][0][0])
        res.y=max(res.y,h[x][0][0]);
    x=p[x][0];
    if(res.x<h[y][0][0]){
        res.y=max(res.x,h[y][0][1]);
        res.x=h[y][0][0];
    }
    if(res.x==h[y][0][0])
        res.y=max(res.y,h[y][0][1]);
    if(res.x>h[y][0][0])
        res.y=max(res.y,h[y][0][0]);
    y=p[y][0];
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
    sort(edge+1,edge+m+1,cmp);
    for(int i=1;i<=n;i++)
        f[i]=i;
    for(int i=1;i<=m;i++){
        int fu=father(edge[i].u),fv=father(edge[i].v);
        if(fu!=fv){
            f[fv]=fu;
            sum+=edge[i].w;
            g[edge[i].u].push_back({edge[i].v,edge[i].w});
            g[edge[i].v].push_back({edge[i].u,edge[i].w});
        }
    }
    memset(h,0xcf,sizeof(h));
    dfs(1,0);
    for(int i=1;i<=m;i++){
        if(edge[i].u==edge[i].v)
            continue;
        pii res=LCA(edge[i].u,edge[i].v);
        if(res.x<edge[i].w)
            ans=min(ans,sum-res.x+edge[i].w);
        else if(res.y>0)
            ans=min(ans,sum-res.y+edge[i].w);
    }
    printf("%lld",ans);
    return 0;
}
